using System;

class Person
{
    private string name;
    public int Age { get; set; }

    public Person(string name, int age)
    {
        this.name = name;
        Age = age;
    }

    public string GetName()
    {
        return name;
    }

    public void SetName(string newName)
    {
        if (!string.IsNullOrEmpty(newName))
            name = newName;
    }
}

class Program
{
    static void Main(string[] args)
    {
        Person person = new Person("Aysel", 25);
        Console.WriteLine($"Ad: {person.GetName()}, Yaş: {person.Age}");
        person.SetName("Kamal");
        Console.WriteLine($"Yeni ad: {person.GetName()}");
        // person.name = "Səhv"; // Səhv: name private olduğu üçün əlçatan deyil
    }
}
// Output:
// Ad: Aysel, Yaş: 25
// Yeni ad: Kamal

using System;

class BankAccount
{
    private decimal balance;

    public decimal Balance
    {
        get { return balance; }
        set
        {
            if (value >= 0)
                balance = value;
        }
    }

    public BankAccount(decimal initialBalance)
    {
        Balance = initialBalance;
    }

    public void Deposit(decimal amount)
    {
        if (amount > 0)
            Balance += amount;
    }
}

class Program
{
    static void Main(string[] args)
    {
        BankAccount account = new BankAccount(1000);
        Console.WriteLine($"Başlanğıc balans: {account.Balance}");
        account.Deposit(500);
        Console.WriteLine($"Yeni balans: {account.Balance}");
        account.Balance = -100; // Mənfi dəyər qəbul olunmur
        Console.WriteLine($"Balans: {account.Balance}");
    }
}
// Output:
// Başlanğıc balans: 1000
// Yeni balans: 1500
// Balans: 1500

